const input = $input.first().json;
const action = input.action || 'find_nearby';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

// Built-in fallback chain: main + unmetered mirrors (private.coffee has no rate limit,
// kumi.systems is operated by same team). User-set endpoint (if any) goes first.
const DEFAULT_ENDPOINTS = [
  'https://overpass-api.de/api/interpreter',
  'https://overpass.private.coffee/api/interpreter',
  'https://overpass.kumi.systems/api/interpreter'
];

let endpoints = [...DEFAULT_ENDPOINTS];
try {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.overpass-osm&cred_key=eq.overpass_endpoint&select=cred_value',
    headers: pgHeaders
  });
  if (creds && creds[0] && creds[0].cred_value) {
    const custom = creds[0].cred_value.trim();
    endpoints = [custom, ...DEFAULT_ENDPOINTS.filter(e => e !== custom)];
  }
} catch (e) { /* use default chain */ }

async function overpassQuery(ql) {
  const attempts = [];
  for (const url of endpoints) {
    try {
      const resp = await helpers.httpRequest({
        method: 'POST',
        url,
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: 'data=' + encodeURIComponent(ql),
        timeout: 30000
      });
      if (typeof resp === 'string' && resp.trim().startsWith('<')) {
        attempts.push(url + ': rate-limit HTML');
        continue;
      }
      return resp;
    } catch (e) {
      const code = e.response && e.response.status;
      attempts.push(url + ': ' + (code ? 'HTTP ' + code : e.message));
      // 4xx (except 429) = client/query error, don't retry on other mirrors
      if (code && code >= 400 && code < 500 && code !== 429) {
        throw new Error('Overpass rejected query (HTTP ' + code + '). Likely a syntax error in the Overpass QL.');
      }
      // 429/5xx/network/timeout -> try next mirror
    }
  }
  throw new Error('All Overpass endpoints unavailable. Attempts: ' + attempts.join('; '));
}

const PRESETS = {
  restaurant: { type: 'amenity', value: 'restaurant', label: 'Restaurants' },
  cafe: { type: 'amenity', value: 'cafe', label: 'Cafes' },
  bar: { type: 'amenity', value: 'bar', label: 'Bars' },
  pub: { type: 'amenity', value: 'pub', label: 'Pubs' },
  fast_food: { type: 'amenity', value: 'fast_food', label: 'Fast food' },
  biergarten: { type: 'amenity', value: 'biergarten', label: 'Beer gardens' },
  hotel: { type: 'tourism', value: 'hotel', label: 'Hotels' },
  guest_house: { type: 'tourism', value: 'guest_house', label: 'Guest houses' },
  hostel: { type: 'tourism', value: 'hostel', label: 'Hostels' },
  alpine_hut: { type: 'tourism', value: 'alpine_hut', label: 'Alpine huts' },
  supermarket: { type: 'shop', value: 'supermarket', label: 'Supermarkets' },
  bakery: { type: 'shop', value: 'bakery', label: 'Bakeries' },
  pharmacy: { type: 'amenity', value: 'pharmacy', label: 'Pharmacies' },
  attraction: { type: 'tourism', value: 'attraction', label: 'Attractions' },
  museum: { type: 'tourism', value: 'museum', label: 'Museums' },
  gallery: { type: 'tourism', value: 'gallery', label: 'Galleries' },
  information: { type: 'tourism', value: 'information', label: 'Tourist info' },
  parking: { type: 'amenity', value: 'parking', label: 'Parking' },
  fuel: { type: 'amenity', value: 'fuel', label: 'Gas stations' },
  charging_station: { type: 'amenity', value: 'charging_station', label: 'EV charging' },
  atm: { type: 'amenity', value: 'atm', label: 'ATMs' },
  toilets: { type: 'amenity', value: 'toilets', label: 'Public toilets' },
  drinking_water: { type: 'amenity', value: 'drinking_water', label: 'Drinking water' },
  shelter: { type: 'amenity', value: 'shelter', label: 'Shelters' },
  peak: { type: 'natural', value: 'peak', label: 'Mountain peaks' },
  picnic_site: { type: 'tourism', value: 'picnic_site', label: 'Picnic sites' },
  waterfall: { type: 'waterway', value: 'waterfall', label: 'Waterfalls' },
  spring: { type: 'natural', value: 'spring', label: 'Springs' },
  camp_site: { type: 'tourism', value: 'camp_site', label: 'Camp sites' }
};

async function geocode(place) {
  const results = await helpers.httpRequest({
    method: 'GET',
    url: 'https://nominatim.openstreetmap.org/search?q=' + encodeURIComponent(place) + '&format=json&limit=1',
    headers: { 'User-Agent': 'n8n-claw-overpass/1.0' }
  });
  if (!results || results.length === 0) return null;
  return { lat: parseFloat(results[0].lat), lon: parseFloat(results[0].lon), name: results[0].display_name };
}

// === geocode_place ===
if (action === 'geocode_place') {
  const place = input.place;
  if (!place) return [{ json: { error: 'Parameter "place" is required (city, address, or landmark name).' } }];
  try {
    const g = await geocode(place);
    if (!g) return [{ json: { error: 'Place not found: ' + place } }];
    return [{ json: { result: g.name + '\nLat: ' + g.lat + ', Lon: ' + g.lon } }];
  } catch (e) {
    return [{ json: { error: 'Geocoding failed: ' + e.message } }];
  }
}

// === reverse_geocode ===
if (action === 'reverse_geocode') {
  const lat = parseFloat(input.lat);
  const lon = parseFloat(input.lon);
  if (isNaN(lat) || isNaN(lon)) {
    return [{ json: { error: 'Parameters "lat" and "lon" (decimal) are required.' } }];
  }
  try {
    const r = await helpers.httpRequest({
      method: 'GET',
      url: 'https://nominatim.openstreetmap.org/reverse?lat=' + lat + '&lon=' + lon + '&format=json&zoom=18&addressdetails=1',
      headers: { 'User-Agent': 'n8n-claw-overpass/1.0' }
    });
    if (!r || (!r.display_name && !r.address)) {
      return [{ json: { result: 'No address found for ' + lat + ',' + lon + ' (location is likely remote/rural).' } }];
    }
    const a = r.address || {};
    const short = [];
    if (a.road) {
      let s = a.road;
      if (a.house_number) s += ' ' + a.house_number;
      short.push(s);
    }
    const area = a.suburb || a.neighbourhood || a.city_district;
    if (area) short.push(area);
    const place = a.city || a.town || a.village || a.municipality;
    if (place && place !== area) short.push(place);
    if (a.postcode && place) short.unshift(a.postcode + ' ' + place);
    const compact = short.length ? short.join(', ') : (r.display_name || '').split(',').slice(0, 3).join(',').trim();
    return [{ json: { result: compact + '\n(' + lat + ', ' + lon + ')', full: r.display_name || '' } }];
  } catch (e) {
    return [{ json: { error: 'Reverse geocoding failed: ' + e.message } }];
  }
}

// === find_nearby ===
if (action === 'find_nearby') {
  const category = input.category;
  if (!category || !PRESETS[category]) {
    return [{ json: { error: 'Parameter "category" required. Available: ' + Object.keys(PRESETS).join(', ') } }];
  }
  let lat = parseFloat(input.lat);
  let lon = parseFloat(input.lon);
  const radius = parseInt(input.radius) || 1000;
  const limit = parseInt(input.limit) || 15;

  if ((isNaN(lat) || isNaN(lon)) && input.place) {
    try {
      const g = await geocode(input.place);
      if (!g) return [{ json: { error: 'Place not found: ' + input.place } }];
      lat = g.lat; lon = g.lon;
    } catch (e) {
      return [{ json: { error: 'Geocoding failed: ' + e.message } }];
    }
  }
  if (isNaN(lat) || isNaN(lon)) {
    return [{ json: { error: 'Provide either lat+lon (decimal coordinates) or place (city/address name).' } }];
  }

  const preset = PRESETS[category];
  const filter = '["' + preset.type + '"="' + preset.value + '"]';
  const around = '(around:' + radius + ',' + lat + ',' + lon + ')';
  const ql = '[out:json][timeout:25];(node' + filter + around + ';way' + filter + around + ';relation' + filter + around + ';);out center ' + limit + ';';

  let resp;
  try {
    resp = await overpassQuery(ql);
  } catch (e) {
    return [{ json: { error: e.message } }];
  }

  const elements = (resp && resp.elements) || [];
  if (elements.length === 0) {
    return [{ json: { result: 'No ' + preset.label.toLowerCase() + ' found within ' + radius + 'm of (' + lat.toFixed(4) + ',' + lon.toFixed(4) + ').' } }];
  }

  // Auto-enrich unnamed/addressless results with reverse geocoding (top 3, respects Nominatim 1 req/s)
  const shown = elements.slice(0, limit);
  const reverseMap = {};
  const toReverse = [];
  for (let i = 0; i < shown.length; i++) {
    const el = shown[i];
    const tags = el.tags || {};
    const hasName = tags.name || tags['name:en'] || tags.brand;
    const hasAddr = tags['addr:street'];
    if (!hasName && !hasAddr && toReverse.length < 3) toReverse.push(i);
  }
  for (let j = 0; j < toReverse.length; j++) {
    if (j > 0) await new Promise(r => setTimeout(r, 1100));
    const idx = toReverse[j];
    const el = shown[idx];
    const elLat = el.lat || (el.center && el.center.lat);
    const elLon = el.lon || (el.center && el.center.lon);
    if (!elLat || !elLon) continue;
    try {
      const rev = await helpers.httpRequest({
        method: 'GET',
        url: 'https://nominatim.openstreetmap.org/reverse?lat=' + elLat + '&lon=' + elLon + '&format=json&zoom=18&addressdetails=1',
        headers: { 'User-Agent': 'n8n-claw-overpass/1.0' }
      });
      const a = (rev && rev.address) || {};
      const bits = [];
      if (a.road) {
        let s = a.road;
        if (a.house_number) s += ' ' + a.house_number;
        bits.push(s);
      }
      const area = a.suburb || a.neighbourhood || a.city_district;
      if (area) bits.push(area);
      if (bits.length) reverseMap[idx] = bits.join(', ');
    } catch (e) { /* best-effort */ }
  }

  let out = preset.label + ' within ' + radius + 'm of (' + lat.toFixed(4) + ',' + lon.toFixed(4) + ') - ' + elements.length + ' results:\n\n';
  for (let i = 0; i < shown.length; i++) {
    const el = shown[i];
    const tags = el.tags || {};
    const name = tags.name || tags['name:en'] || tags.brand || '(unnamed)';
    const elLat = el.lat || (el.center && el.center.lat);
    const elLon = el.lon || (el.center && el.center.lon);
    out += '- ' + name;
    if (tags.cuisine) out += ' [' + tags.cuisine + ']';
    if (tags.stars) out += ' [' + tags.stars + ' stars]';
    if (tags.ele) out += ' [' + tags.ele + 'm]';
    if (elLat && elLon) out += ' (' + Number(elLat).toFixed(4) + ',' + Number(elLon).toFixed(4) + ')';
    out += '\n';
    const details = [];
    if (tags['addr:street']) {
      let addr = tags['addr:street'];
      if (tags['addr:housenumber']) addr += ' ' + tags['addr:housenumber'];
      details.push(addr);
    } else if (reverseMap[i]) {
      details.push('Near: ' + reverseMap[i]);
    }
    if (tags.opening_hours) details.push('Hours: ' + tags.opening_hours);
    if (tags.phone) details.push('Tel: ' + tags.phone);
    if (tags.website) details.push(tags.website);
    if (tags.wheelchair && tags.wheelchair !== 'no') details.push('Wheelchair: ' + tags.wheelchair);
    if (tags.internet_access) details.push('WiFi: ' + tags.internet_access);
    if (tags.fee) details.push('Fee: ' + tags.fee);
    if (details.length) out += '  ' + details.join(' | ') + '\n';
  }

  if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
  return [{ json: { result: out } }];
}

// === search_custom ===
if (action === 'search_custom') {
  const query = input.query;
  if (!query) {
    return [{ json: { error: 'Parameter "query" (Overpass QL) is required. Example: [out:json][timeout:25];node[amenity=cafe](around:500,51.4124,7.0018);out;' } }];
  }
  let resp;
  try {
    resp = await overpassQuery(query);
  } catch (e) {
    return [{ json: { error: e.message } }];
  }
  const elements = (resp && resp.elements) || [];
  let out = 'Overpass result: ' + elements.length + ' elements\n\n';
  for (const el of elements.slice(0, 20)) {
    const tags = el.tags || {};
    const name = tags.name || '(unnamed)';
    const elLat = el.lat || (el.center && el.center.lat);
    const elLon = el.lon || (el.center && el.center.lon);
    out += '- [' + el.type + '/' + el.id + '] ' + name;
    if (elLat && elLon) out += ' (' + Number(elLat).toFixed(4) + ',' + Number(elLon).toFixed(4) + ')';
    out += '\n';
    const topTags = ['amenity', 'tourism', 'shop', 'natural', 'cuisine', 'opening_hours'];
    const tagBits = [];
    for (const k of topTags) if (tags[k]) tagBits.push(k + '=' + tags[k]);
    if (tagBits.length) out += '  ' + tagBits.join(', ') + '\n';
  }
  if (elements.length > 20) out += '\n... and ' + (elements.length - 20) + ' more\n';
  if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
  return [{ json: { result: out } }];
}

return [{ json: { error: 'Unknown action: ' + action + '. Available: geocode_place, find_nearby, search_custom.' } }];
